async function isPartner(userId, text, env) {
  if (text && text.replace(/\s/g, "").includes("\u52A0\u76DF\u5E97\u5E0C\u671B")) {
    try {
      await env.SEEN_STORE.put(
        `partner:${userId}`,
        JSON.stringify({ since: Date.now() }),
        { expirationTtl: 60 * 60 * 24 * 365 }
      );
    } catch (e) {
      console.error("partner put error:", e.message);
    }
    return { partner: true, justJoined: true };
  }
  try {
    const rec = await env.SEEN_STORE.get(`partner:${userId}`);
    if (rec) return { partner: true, justJoined: false };
  } catch (e) {
    console.error("partner get error:", e.message);
  }
  return { partner: false, justJoined: false };
}
